-- Run this if the dashboard shows no student records in your existing database.
USE `naevis_inter_high_db`;

ALTER TABLE `students` ADD COLUMN IF NOT EXISTS `password` varchar(255) DEFAULT 'student123';

ON DUPLICATE KEY UPDATE
  `name`=VALUES(`name`),
  `glvl`=VALUES(`glvl`),
  `section`=VALUES(`section`),
  `strand`=VALUES(`strand`),
  `age`=VALUES(`age`),
  `sex`=VALUES(`sex`),
  `password`=VALUES(`password`),
  `gwa`=VALUES(`gwa`);
